// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract GrandGooseMansion {
    uint256 public supply = 0;
    uint256 public cost = 0.01 ether;
    uint256 public maxSupply = 10000;
    uint256 public preSaleWalletLimit = 10;
    address public owner;
    enum SaleStatus { Paused, Presale, PublicSale }
    SaleStatus public currentSaleStatus = SaleStatus.Paused;
    mapping(address => uint256) private _preSaleWalletMinted;
    mapping(address => bool) private whitelist;

    event Minted(address indexed user, uint256 amount);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    function whitelistUser(address user, bool status) public onlyOwner {
        whitelist[user] = status;
    }

    function startPresale() public onlyOwner {
        require(currentSaleStatus == SaleStatus.Paused, "Sale is not paused");
        currentSaleStatus = SaleStatus.Presale;
    }

    function startPublicSale() public onlyOwner {
        require(currentSaleStatus == SaleStatus.Presale, "Sale is not in presale");
        currentSaleStatus = SaleStatus.PublicSale;
    }

    function setCost(uint256 newCost) public onlyOwner {
        cost = newCost;
    }

    function isWhitelisted(address user) public view returns (bool) {
        return whitelist[user];
    }

    function mintTokenWhitelisted(uint256 amount) public payable {
        require(currentSaleStatus == SaleStatus.Presale, "Presale is not active");
        require(whitelist[msg.sender], "Not whitelisted");
        require(amount > 0, "Amount must be greater than zero");
        require(_preSaleWalletMinted[msg.sender] + amount <= preSaleWalletLimit, "Exceeds wallet limit");
        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(msg.value == amount * cost, "Exact payment required");

        supply += amount;
        _preSaleWalletMinted[msg.sender] += amount;
        emit Minted(msg.sender, amount);
    }

    function mintTokenPublic(uint256 amount) public payable {
        require(currentSaleStatus == SaleStatus.PublicSale, "Public sale is not active");
        require(amount > 0, "Amount must be greater than zero");
        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(msg.value == amount * cost, "Exact payment required");

        supply += amount;
        emit Minted(msg.sender, amount);
    }

    function preSaleWalletMinted(address user) public view returns (uint256) {
        return _preSaleWalletMinted[user];
    }
}
